#include <stdio.h>
#include <stdlib.h>
#include <ctype.h>
#include <string.h>
#include "slothvm.h"
int progLen(FILE* f){
  char c;
  int count = 0;
  for (c = getc(f); c != EOF; c = getc(f)){
    if (c == '\n'){
      count = count + 1;
    }
  }
  fseek(f, 0, SEEK_SET);
  return count * 3;
}
void freeProgram(struct sloth_program* P){
  free(P->codes);
  free(P);
}
char *readline(FILE *file){

  const size_t default_len = 100;
  char *line = malloc(sizeof(char) * default_len);
  size_t len = default_len;
  size_t currentChar = 0;
  char c = '\0';
  while(c != -1){
    c = fgetc(file);

    if(currentChar == len){
      len *= 2;
      line = realloc(line, len);
    }
    if(c == '\n'){
      break;
    }
    line[currentChar] = c;
    currentChar++;
  }

  if(c == -1){
    line[currentChar] = -1;
    currentChar++;
  }
  line[currentChar] = '\0';
  return line;
}
struct sloth_program* parse(char* filepath){
  FILE* sFile;
  sFile = fopen(filepath, "r");
  if(sFile == NULL){
    fprintf(stderr, "[ERROR] File could not be opened.");
    exit(1);
  }
  int numCodes = progLen(sFile);
  ubyte* byteCode = malloc(sizeof(char) * numCodes);
  char c = '\0';
  size_t count = 0;
  char *line = 0x0;
  size_t len = 0;
  size_t codeNum = 0;
  unsigned char currentCode = 0;
  char hadToken = 0;
  while(1){
    count = 0;
    currentCode = 0;
    line = readline(sFile);
    len = strlen(line);

    if(line[0] == -1){
      free(line);
      break;
    }
    if(len == 0){
      free(line);
      continue;
    }

    c = line[0];
    while(c != 0 && c != -1 && c != '#' && count <= len){

      if(strncmp("slothy", line + count, 6) == 0){
	byteCode[codeNum] = 0x1;
	codeNum++;
	count += 6;
  hadToken = 1;
      } else if(strncmp("sloth", line + count, 5) == 0){
	currentCode++;
	count += 5;
  hadToken = 1;
      }else if(strncmp("and", line + count, 3) == 0){
	byteCode[codeNum] = currentCode;
	codeNum++;
	currentCode = 0;
	count += 3;
  hadToken = 1;
      }else if(strncmp("nap", line + count, 3) == 0){
	byteCode[codeNum] = 0x0;
	codeNum++;
	count += 3;
  hadToken = 1;
      }else{

	count++;
      }
      c = line[count];
    }
    if(hadToken){
    byteCode[codeNum] = currentCode;
    codeNum++;
    hadToken = 0;
    }
    free(line);
  }
  struct sloth_program* S = malloc(sizeof(struct sloth_program));
  S->codes = byteCode;
  return S;
}
